import React from 'react'
import './styles/Subheader.css'
const SubHeader = () => {
  return (
    <div>
      <h2>Select Themes You Love </h2>
      <div className='tagsRequirment'> You should choose at least <span>3</span> themes to <br /> set up your recommendation </div>
    </div>
  )
}

export default SubHeader
